import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

export default function MoviePage() {
  const { API } = useAuth();
  const { id } = useParams();
  const [movie, setMovie] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    axios
      .get(`${API}/movies/${id}`)
      .then((res) => setMovie(res.data))
      .catch(() => setError('Movie not found'));
  }, [API, id]);

  if (error) return <main className="page" style={{ padding: '100px 24px' }}>{error}</main>;
  if (!movie) return <main className="page" style={{ padding: '100px 24px' }}>Loading movie...</main>;

  return (
    <main className="page" style={{ paddingTop: '68px' }}>
      <div
        style={{
          minHeight: '46vh',
          backgroundImage: `linear-gradient(to top, rgba(5,5,5,1), rgba(5,5,5,0.25)), url(${movie.backdrop || movie.thumbnail})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          display: 'flex',
          alignItems: 'end',
          padding: '32px 24px',
        }}
      >
        <div>
          <h1 style={{ fontFamily: 'var(--font-display)', letterSpacing: '2px', fontSize: '3rem' }}>{movie.title}</h1>
          <div style={{ color: 'var(--text-dim)' }}>{movie.year} • {movie.duration || '-'} min • {movie.rating?.toFixed(1) || 'N/A'}</div>
        </div>
      </div>
      <section style={{ padding: '24px' }}>
        <p style={{ maxWidth: '900px', color: 'var(--text-dim)', lineHeight: 1.7 }}>{movie.description}</p>
      </section>
    </main>
  );
}
